code.perFrame:
zoom = 0.99998;
rot = 0;
dx = 0;
dy = 0;
sx = 0.99817;
sy = 0.99999;
warp = 0.10892;
cx = 0.5;
cy = 0.5;
q1=aspecty;   decay=1;   warp=0;     zoom=.001;   wave_a=0;;
q2=.5+.4*sin(.33*time);    q3=.5+.4*sin(.51*time);    //// ball coordinates;
q4=2+sin(.12*time);    //// zoom;
p=20000;   i=0;    loop(2900,;
x=-.0014*gmegabuf(i)/q1-.02*time;   x=int(x+1)-x;;
