r=.8+.2*sin(10*d-4*time);     g=.5+.5*sin(7*d-3*time);;
a=.5+.3*sin(3*d-time)+.3*sin(3*ang+time);;
gmegabuf(p+6*i)=x;    gmegabuf(p+6*i+1)=y;    gmegabuf(p+6*i+2)=r;;
gmegabuf(p+6*i+3)=g;  gmegabuf(p+6*i+4)=a;    gmegabuf(p+6*i+5)=ang;;
i=i+1;);
